import{_ as o,H as e,f as a,i as r}from"./chunks/framework.Cvt1eIE0.js";const h=JSON.parse('{"title":"高级设置 (Advanced Settings)","description":"","frontmatter":{},"headers":[],"relativePath":"store-locator/guide/advanced-settings.md","filePath":"store-locator/guide/advanced-settings.md"}'),s={name:"store-locator/guide/advanced-settings.md"};function n(i,t,c,l,d,g){return e(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="高级设置-advanced-settings" tabindex="-1">高级设置 (Advanced Settings) <a class="header-anchor" href="#高级设置-advanced-settings" aria-label="Permalink to &quot;高级设置 (Advanced Settings)&quot;">​</a></h1><p>在 <strong>Settings &gt; Advanced Settings</strong> 菜单中，您可以配置定位器的高级功能。 <em>注：高级设置包含部分高级功能，可能需要 Pro 以上套餐支持。</em></p><h2 id="_1-storefront-access-前端访问路径" tabindex="-1">1. Storefront Access (前端访问路径) <a class="header-anchor" href="#_1-storefront-access-前端访问路径" aria-label="Permalink to &quot;1. Storefront Access (前端访问路径)&quot;">​</a></h2><p>这里显示了 Store Locator 的公共代理路径（通常为 <code>/apps/store-finder</code>）以及您专属的 <strong>Public map URL</strong>（如 <code>/pages/store-locator</code>）。 您可以点击 <strong>Copy</strong> 直接复制页面链接，方便在您的网站导航或底部链接中进行配置。</p><h2 id="_2-customer-location-客户位置与距离计算" tabindex="-1">2. Customer Location (客户位置与距离计算) <a class="header-anchor" href="#_2-customer-location-客户位置与距离计算" aria-label="Permalink to &quot;2. Customer Location (客户位置与距离计算)&quot;">​</a></h2><p>开启 <strong>Enable customer location and distance</strong> 可以大幅提升用户体验：</p><ul><li><strong>自动定位功能</strong>：允许在前端显示“定位我”按钮。用户点击后，只要授权了浏览器的定位权限，地图就能以用户为中心。</li><li><strong>距离计算</strong>：启用后，系统会调用 Google Geocoding API 自动计算出从用户位置到周围每家门店的实际距离，并在门店列表中显示。</li></ul><p><strong>Appearance Styling (外观自定义)</strong> 开启上述功能后，您还可以精细化调整相关 UI 的颜色：</p><ul><li><strong>Location Pin Color</strong>：自定义代表“用户当前位置”的大头针图标颜色。</li><li><strong>Distance Labels</strong>：自定义距离标签的背景色 (Background)、边框色 (Border) 以及文本颜色 (Text)。</li></ul><h2 id="_3-map-behaviors-地图动态交互" tabindex="-1">3. Map Behaviors (地图动态交互) <a class="header-anchor" href="#_3-map-behaviors-地图动态交互" aria-label="Permalink to &quot;3. Map Behaviors (地图动态交互)&quot;">​</a></h2><p>开启 <strong>Filter stores by map area (按地图区域过滤门店)</strong>。 这是一个非常实用的高级交互功能：当用户在地图上进行拖拽 (Pan) 或缩放 (Zoom) 时，<strong>左侧的门店列表会自动刷新</strong>，仅仅显示当前可视地图区域内的门店。这在门店数量众多时，可以极大地提升查找效率和前端性能。</p><h2 id="_4-system-info-系统状态" tabindex="-1">4. System Info (系统状态) <a class="header-anchor" href="#_4-system-info-系统状态" aria-label="Permalink to &quot;4. System Info (系统状态)&quot;">​</a></h2><p>在右下角的卡片中，您可以随时查看应用的当前运行状态：</p><ul><li><strong>Version</strong>：当前应用的构建版本号。</li><li><strong>Database</strong>：D1 云端数据库连接状态。</li><li><strong>Shop</strong>：您当前绑定的 Shopify 店铺域名。</li></ul>',14)])])}const u=o(s,[["render",n]]);export{h as __pageData,u as default};
